const WORDS_ADDITIONS = [
// ==================== 整形外科 ORTHO ====================
{ en:"Knee effusion", de:"Kniegelenkerguss", abbr:"", ja:"膝関節水腫", note:"膝関節内への液体貯留。外傷・関節炎・痛風・感染で出現。浮き膝（ballottement）で確認。", example:"Knee effusion was aspirated and sent for analysis.", cat:"diagnosis", level:"basic", dept:"ORTHO" },
{ en:"Valgus deformity", de:"Valgusfehlstellung", abbr:"", ja:"外反変形", note:"関節の遠位部が外側に偏位する変形。膝外反（X脚）・外反母趾が代表的。", example:"Valgus deformity of the knee was corrected with a high tibial osteotomy.", cat:"diagnosis", level:"intermediate", dept:"ORTHO" },
{ en:"Varus deformity", de:"Varusfehlstellung", abbr:"", ja:"内反変形", note:"関節の遠位部が内側に偏位する変形。膝内反（O脚）が代表的。変形性膝関節症に多い。", example:"Varus deformity was confirmed on weight-bearing X-ray.", cat:"diagnosis", level:"intermediate", dept:"ORTHO" },
{ en:"Bone spur", de:"Knochensporn", abbr:"", ja:"骨棘（こつきょく）", note:"関節縁・腱付着部に生じる骨の突起。変形性関節症・慢性付着部炎で形成。", example:"Bone spurs on the calcaneus caused pain with the first steps in the morning.", cat:"diagnosis", level:"basic", dept:"ORTHO" },
{ en:"Joint space narrowing", de:"Gelenkspaltverschmälerung", abbr:"", ja:"関節裂隙狭小化", note:"X線所見。関節軟骨の摩耗・消失を示す。変形性関節症・関節リウマチの評価に使用。", example:"Joint space narrowing was present medially, consistent with osteoarthritis.", cat:"diagnosis", level:"intermediate", dept:"ORTHO" },
{ en:"Subchondral sclerosis", de:"Subchondrale Sklerose", abbr:"", ja:"軟骨下骨硬化", note:"X線所見。関節軟骨下の骨密度増加。変形性関節症の進行を示す所見。", example:"Subchondral sclerosis and cyst formation indicated severe osteoarthritis.", cat:"diagnosis", level:"intermediate", dept:"ORTHO" },
{ en:"Muscle spasm", de:"Muskelspasmus", abbr:"", ja:"筋攣縮（マッスルスパズム）", note:"筋肉の不随意的な持続収縮。腰痛・頸部痛・外傷後に多い。温熱・マッサージ・筋弛緩薬で治療。", example:"Muscle spasm in the lower back was relieved with heat therapy and NSAIDs.", cat:"symptom", level:"basic", dept:"ORTHO" },
{ en:"Postoperative stiffness", de:"Postoperative Steifigkeit", abbr:"", ja:"術後関節拘縮", note:"手術後の関節可動域制限。早期リハビリ・関節モビライゼーションで予防・治療。", example:"Postoperative stiffness was managed with intensive physical therapy.", cat:"diagnosis", level:"intermediate", dept:"ORTHO" },
{ en:"Malunion", de:"Fehlverheilung", abbr:"", ja:"変形癒合（偽関節ではない）", note:"骨折が変形位で癒合した状態。機能障害・疼痛が残存する場合は矯正骨切り術が必要。", example:"Malunion of the radius caused limited forearm rotation and required corrective osteotomy.", cat:"diagnosis", level:"intermediate", dept:"ORTHO" },
{ en:"Nonunion", de:"Pseudarthrose", abbr:"", ja:"偽関節（骨折不癒合）", note:"骨折後6ヶ月以上経過しても骨癒合が得られない状態。電気刺激・骨移植・手術が治療。", example:"Nonunion of the tibial shaft required bone grafting and revision fixation.", cat:"diagnosis", level:"intermediate", dept:"ORTHO" },
{ en:"Delayed union", de:"Verzögerte Knochenheilung", abbr:"", ja:"遷延癒合", note:"通常の骨癒合期間を超えても癒合が遅れている状態。感染・栄養不良・喫煙が原因。", example:"Delayed union was suspected when the fracture showed no callus at 3 months.", cat:"diagnosis", level:"intermediate", dept:"ORTHO" },
{ en:"Cast removal", de:"Gipsabnahme", abbr:"", ja:"ギプス除去", note:"ギプスカッターで安全に除去。皮膚・筋萎縮・関節拘縮を評価後にリハビリ開始。", example:"Cast removal revealed skin atrophy and limited range of motion requiring rehabilitation.", cat:"treatment", level:"basic", dept:"ORTHO" },
{ en:"Orthosis", de:"Orthese", abbr:"", ja:"装具（オルソーシス）", note:"関節の支持・矯正・固定を目的とした外部装具。AFO・KAFO・頸椎カラーなど。", example:"A knee orthosis was prescribed to support the ligament-deficient joint.", cat:"treatment", level:"basic", dept:"ORTHO" },
{ en:"Prosthesis", de:"Prothese", abbr:"", ja:"義肢・人工関節", note:"切断肢の義肢または人工関節の総称。機能回復・QOL改善が目的。リハビリが重要。", example:"A below-knee prosthesis was fitted after the traumatic amputation.", cat:"treatment", level:"basic", dept:"ORTHO" },
{ en:"Amputation level", de:"Amputationshöhe", abbr:"", ja:"切断レベル", note:"切断肢の断端部位。BK（膝下）/ AK（膝上）/ Syme（足関節部）などで表現。義肢装着に影響。", example:"The amputation level was determined to preserve maximum functional length.", cat:"diagnosis", level:"intermediate", dept:"ORTHO" },
{ en:"Stump care", de:"Stumpfpflege", abbr:"", ja:"断端管理", note:"切断後の断端形成・皮膚ケア・浮腫管理。弾性包帯・断端シェイパーで義肢装着を準備。", example:"Stump care included daily inspection, cleaning, and elastic bandaging.", cat:"treatment", level:"intermediate", dept:"ORTHO" },
{ en:"Phantom limb pain", de:"Phantomschmerz", abbr:"", ja:"幻肢痛", note:"切断後も失った肢に疼痛を感じる現象。ミラーセラピー・薬物療法・神経ブロックで治療。", example:"Phantom limb pain was managed with pregabalin and mirror therapy.", cat:"symptom", level:"intermediate", dept:"ORTHO" },
{ en:"Heterotopic ossification", de:"Heterotope Ossifikation", abbr:"HO", ja:"異所性骨化", note:"骨以外の組織（筋肉・関節周囲）への骨形成。TBI・脊損・股関節手術後に多い。関節拘縮の原因。", example:"Heterotopic ossification around the hip was treated with radiation prophylaxis.", cat:"diagnosis", level:"advanced", dept:"ORTHO" },
{ en:"Gait training", de:"Gangschulung", abbr:"", ja:"歩行訓練", note:"骨折・手術・神経障害後の歩行再獲得のためのリハビリ。免荷歩行から全荷重へ段階的に進める。", example:"Gait training with partial weight-bearing was started on postoperative day 2.", cat:"treatment", level:"basic", dept:"ORTHO" },
{ en:"Muscle testing", de:"Muskelfunktionsprüfung", abbr:"MMT", ja:"徒手筋力検査", note:"Manual Muscle Testing。0〜5の6段階で筋力を評価。神経・筋疾患・術後評価に使用。", example:"Muscle testing showed grade 3 quadriceps strength after the knee surgery.", cat:"diagnosis", level:"basic", dept:"ORTHO" },
{ en:"Waddell signs", de:"Waddell-Zeichen", abbr:"", ja:"ワデル徴候", note:"腰痛の非器質的因子（心理社会的要因）を評価する5徴候。3つ以上陽性で非器質的要素を示唆。", example:"Three positive Waddell signs suggested a significant psychological component to the pain.", cat:"diagnosis", level:"advanced", dept:"ORTHO" },
{ en:"Yellow flags", de:"Gelbe Flaggen", abbr:"", ja:"黄色フラグ（心理社会的因子）", note:"慢性腰痛への移行リスク因子。恐怖回避行動・破局的思考・抑うつ・仕事への不満など。", example:"Yellow flags were identified and addressed with cognitive behavioral therapy.", cat:"common", level:"intermediate", dept:"ORTHO" },
{ en:"Kinesiophobia", de:"Kinesiophobie", abbr:"", ja:"運動恐怖症", note:"運動・活動が疼痛・損傷を悪化させるという過剰な恐怖。慢性疼痛の維持因子。", example:"Kinesiophobia was addressed with graded exposure therapy.", cat:"diagnosis", level:"intermediate", dept:"ORTHO" },
// ==================== 救急科 ER ====================
{ en:"Rapid assessment", de:"Schnelle Beurteilung", abbr:"", ja:"迅速評価", note:"救急患者の15〜30秒での最初の印象評価。意識・気道・呼吸・循環を一瞬で把握。", example:"Rapid assessment revealed an unconscious patient in respiratory distress.", cat:"common", level:"basic", dept:"ER" },
{ en:"Mechanism of injury", de:"Unfallmechanismus", abbr:"MOI", ja:"受傷機転", note:"外傷の発生メカニズム。高エネルギー（交通事故・高所転落）/ 低エネルギーを分類して重症度を予測。", example:"The mechanism of injury was a high-speed motor vehicle collision with airbag deployment.", cat:"diagnosis", level:"basic", dept:"ER" },
{ en:"Penetrating trauma", de:"Penetrierendes Trauma", abbr:"", ja:"穿通性外傷", note:"刺傷・銃創などによる体腔への貫通損傷。臓器損傷・出血が問題。手術適応の評価が重要。", example:"Penetrating trauma to the chest required emergent surgical exploration.", cat:"diagnosis", level:"intermediate", dept:"ER" },
{ en:"Blunt trauma", de:"Stumpfes Trauma", abbr:"", ja:"鈍的外傷", note:"体表面への衝撃による外傷。交通事故・転倒が多い。内臓損傷が体表から見えにくい点が特徴。", example:"Blunt abdominal trauma was evaluated with FAST ultrasound.", cat:"diagnosis", level:"basic", dept:"ER" },
{ en:"Polytrauma", de:"Polytrauma", abbr:"", ja:"多発外傷", note:"2か所以上の重篤な外傷。ISS>16の重症外傷。ダメージコントロール手術が基本。", example:"Polytrauma with chest, abdominal, and orthopedic injuries required a multidisciplinary approach.", cat:"diagnosis", level:"intermediate", dept:"ER" },
{ en:"Damage control surgery", de:"Damage-Control-Chirurgie", abbr:"DCS", ja:"ダメージコントロール手術", note:"出血・汚染コントロールのみ行い腹部を一時閉鎖。ICU安定化後に根治手術。", example:"Damage control surgery controlled the bleeding and the abdomen was packed and temporarily closed.", cat:"treatment", level:"advanced", dept:"ER" },
{ en:"Focused abdominal sonography", de:"Focused Abdominal Sonography for Trauma", abbr:"FAST", ja:"外傷FAST", note:"外傷での腹腔内出血・心嚢液をベッドサイドで迅速評価。4部位（肝腎・脾腎・骨盤・心嚢）。", example:"FAST examination showed free fluid in Morrison's pouch, indicating intra-abdominal hemorrhage.", cat:"diagnosis", level:"intermediate", dept:"ER" },
{ en:"Extended FAST", de:"Erweitertes FAST", abbr:"eFAST", ja:"拡張FAST（胸部含む）", note:"FASPに胸部（気胸・血胸）評価を追加。外傷での胸腹部出血・気胸を迅速スクリーニング。", example:"eFAST detected a left pneumothorax in the trauma patient.", cat:"diagnosis", level:"intermediate", dept:"ER" },
{ en:"Tension pneumothorax", de:"Spannungspneumothorax", abbr:"", ja:"緊張性気胸", note:"胸腔内圧の上昇による縦隔偏位・静脈還流障害。針減圧→胸腔ドレナージが治療。臨床診断が優先。", example:"Tension pneumothorax was immediately decompressed with a needle thoracostomy.", cat:"diagnosis", level:"intermediate", dept:"ER" },
{ en:"Needle decompression", de:"Nadelentlastung", abbr:"", ja:"針胸腔穿刺（減圧）", note:"緊張性気胸の緊急処置。第2肋間鎖骨中線または第4・5肋間前腋窩線に14G針を刺入。", example:"Needle decompression was performed at the second intercostal space, midclavicular line.", cat:"treatment", level:"intermediate", dept:"ER" },
{ en:"Pericardiocentesis", de:"Perikardpunktion", abbr:"", ja:"心嚢穿刺", note:"心タンポナーデへの緊急処置。剣状突起下アプローチ。超音波ガイド下が安全。", example:"Emergency pericardiocentesis relieved the cardiac tamponade.", cat:"treatment", level:"advanced", dept:"ER" },
{ en:"Thoracotomy in ED", de:"Notfallthorakotomie", abbr:"EDT", ja:"救急室開胸術", note:"外傷性心停止への最終手段。生存率は低いが唯一の救命手段になりえる。", example:"An emergency department thoracotomy was performed for traumatic cardiac arrest.", cat:"treatment", level:"advanced", dept:"ER" },
{ en:"Spinal immobilization", de:"Wirbelsäulenimmobilisierung", abbr:"", ja:"脊椎固定", note:"外傷での頸椎・脊椎損傷を疑う場合の固定。頸椎カラー・スパインボード・ログロール。", example:"Spinal immobilization was maintained until the cervical spine was cleared radiologically.", cat:"treatment", level:"basic", dept:"ER" },
{ en:"Log roll", de:"Log-Roll-Technik", abbr:"", ja:"ログロール（丸太転がし）", note:"脊椎損傷疑い患者の体位変換技術。頭・体幹・足部を同一軸で回転させる。4人で実施が理想。", example:"A log roll was performed to examine the patient's back for injuries.", cat:"treatment", level:"basic", dept:"ER" },
{ en:"Cervical spine clearance", de:"HWS-Freigabe", abbr:"", ja:"頸椎クリアランス", note:"頸椎損傷を除外する評価。NEXUS基準・カナダ頸椎規則を用いてX線・CT撮影の要否を判断。", example:"Cervical spine clearance was achieved clinically using the NEXUS criteria.", cat:"diagnosis", level:"intermediate", dept:"ER" },
{ en:"Burn surface area", de:"Verbrennungsfläche", abbr:"TBSA", ja:"熱傷面積（体表面積%）", note:"9の法則（頭9%・上肢各9%・体幹前面18%・後面18%・下肢各18%・会陰1%）で評価。", example:"Burns covered 27% of total body surface area, requiring ICU admission.", cat:"diagnosis", level:"intermediate", dept:"ER" },
{ en:"Burn depth", de:"Verbrennungstiefe", abbr:"", ja:"熱傷深度", note:"I度（発赤）/ II度浅達性（水疱）/ II度深達性（白色・感覚鈍麻）/ III度（壊死・無感覚）。", example:"Deep partial-thickness burns required skin grafting.", cat:"diagnosis", level:"intermediate", dept:"ER" },
{ en:"Escharotomy", de:"Escharotomie", abbr:"", ja:"焼痂切開術", note:"深達性環状熱傷での末梢循環障害に対する焼痂縦切開。コンパートメント症候群を予防。", example:"Escharotomy was performed on the circumferential arm burn to restore circulation.", cat:"treatment", level:"advanced", dept:"ER" },
{ en:"Drowning resuscitation", de:"Ertrinkungsreanimation", abbr:"", ja:"溺水蘇生", note:"溺水後の蘇生。低体温保護効果がある場合は積極的蘇生。「温かくなるまで死亡と判定しない」。", example:"Drowning resuscitation continued aggressively due to cold water submersion.", cat:"treatment", level:"intermediate", dept:"ER" },
{ en:"Crush injury", de:"Quetschverletzung", abbr:"", ja:"挫滅損傷（クラッシュ症候群）", note:"長時間の圧迫解除後の横紋筋融解・高K血症・急性腎障害。大量補液による予防が重要。", example:"Crush injury syndrome was managed with aggressive IV hydration to prevent renal failure.", cat:"diagnosis", level:"intermediate", dept:"ER" },
{ en:"Blast injury", de:"Explosionsverletzung", abbr:"", ja:"爆傷", note:"爆風圧・破片・熱・二次外傷の組み合わせ。肺・耳・腸管が気圧波で損傷（primary blast injury）。", example:"Blast injury caused bilateral tympanic membrane ruptures and pulmonary contusions.", cat:"diagnosis", level:"advanced", dept:"ER" },
// ==================== 循環器内科 CV ====================
{ en:"Cardiac enzymes", de:"Herzenzyme", abbr:"", ja:"心筋逸脱酵素", note:"CK-MB・トロポニンI/T・ミオグロビン。AMI発症後の経時的変化で診断・梗塞サイズを推定。", example:"Serial cardiac enzymes showed a rising pattern consistent with NSTEMI.", cat:"diagnosis", level:"basic", dept:"CV" },
{ en:"STEMI management", de:"STEMI-Behandlung", abbr:"", ja:"STEMI管理", note:"Door-to-balloon time<90分が目標。アスピリン+P2Y12阻害薬+ヘパリン投与後に緊急PCI。", example:"STEMI management included dual antiplatelet therapy and emergent PCI.", cat:"treatment", level:"intermediate", dept:"CV" },
{ en:"Reperfusion therapy", de:"Reperfusionstherapie", abbr:"", ja:"再灌流療法", note:"閉塞冠動脈の血流再開。Primary PCI（第一選択）/ 線溶療法（PCI不可時）。時間が重要。", example:"Reperfusion therapy was achieved with primary PCI within 75 minutes of symptom onset.", cat:"treatment", level:"intermediate", dept:"CV" },
{ en:"Door-to-balloon time", de:"Door-to-Balloon-Zeit", abbr:"D2B", ja:"来院〜バルーン拡張時間", note:"STEMI患者の来院からPCIバルーン拡張までの時間。90分以内が品質指標。", example:"Door-to-balloon time was 68 minutes, within the recommended 90-minute target.", cat:"common", level:"intermediate", dept:"CV" },
{ en:"Left ventricular function", de:"Linksventrikuläre Funktion", abbr:"LV function", ja:"左室機能", note:"EF・壁運動・拡張機能で評価。心エコーが標準。EF<40%で収縮機能低下型心不全。", example:"Left ventricular function was assessed by echocardiography, showing an EF of 35%.", cat:"diagnosis", level:"intermediate", dept:"CV" },
{ en:"Wall motion abnormality", de:"Wandbewegungsstörung", abbr:"WMA", ja:"壁運動異常", note:"心エコー所見。虚血・梗塞部位の壁運動低下（hypokinesis）・消失（akinesis）・逆行（dyskinesis）。", example:"Wall motion abnormality in the anterior wall confirmed left anterior descending artery territory ischemia.", cat:"diagnosis", level:"intermediate", dept:"CV" },
{ en:"Diastolic dysfunction", de:"Diastolische Dysfunktion", abbr:"", ja:"拡張機能障害", note:"左室の弛緩・コンプライアンス低下。HFpEF（EF保持型心不全）の病態基盤。高血圧・肥大型心筋症で多い。", example:"Diastolic dysfunction grade II was found on echocardiography.", cat:"diagnosis", level:"intermediate", dept:"CV" },
{ en:"Acute decompensated heart failure", de:"Akut dekompensierte Herzinsuffizienz", abbr:"ADHF", ja:"急性非代償性心不全", note:"心不全の急性増悪。呼吸困難・起座呼吸・浮腫。利尿薬・血管拡張薬・酸素で治療。", example:"Acute decompensated heart failure was treated with IV furosemide and BiPAP.", cat:"diagnosis", level:"intermediate", dept:"CV" },
{ en:"Cardiac biomarker", de:"Kardiale Biomarker", abbr:"", ja:"心臓バイオマーカー", note:"心筋障害・心不全の診断・モニタリングに使用。トロポニン（心筋壊死）/ BNP・NT-proBNP（心不全）。", example:"Cardiac biomarkers including troponin and BNP were measured on admission.", cat:"diagnosis", level:"basic", dept:"CV" },
{ en:"Holter monitor", de:"Holter-Monitor", abbr:"", ja:"ホルター心電図", note:"24〜48時間の連続心電図記録。動悸・失神・不整脈の診断に使用。日常活動中の変化を評価。", example:"A 48-hour Holter monitor captured episodes of paroxysmal atrial fibrillation.", cat:"diagnosis", level:"basic", dept:"CV" },
{ en:"Event monitor", de:"Event-Recorder", abbr:"", ja:"イベントレコーダー", note:"症状出現時に患者が作動させる携帯型心電図記録。ホルターより長期間の間欠的モニタリング。", example:"An event monitor was prescribed to capture infrequent palpitation episodes.", cat:"diagnosis", level:"intermediate", dept:"CV" },
{ en:"Implantable loop recorder", de:"Implantierbarer Loop-Rekorder", abbr:"ILR", ja:"植込み型ループレコーダー", note:"皮下植込み型長期心電図モニター。原因不明失神・潜因性脳卒中の不整脈評価。最長3年記録。", example:"An implantable loop recorder detected AF in the cryptogenic stroke patient.", cat:"diagnosis", level:"advanced", dept:"CV" },
{ en:"Cardioversion", de:"Kardioversion", abbr:"", ja:"電気的除細動（カルジオバージョン）", note:"同期電気ショックによる不整脈停止。AF・AFL・SVT・VT（脈あり）に適応。ジェル・同期が必須。", example:"Synchronized cardioversion converted the atrial flutter to sinus rhythm.", cat:"treatment", level:"intermediate", dept:"CV" },
{ en:"Ablation", de:"Ablation", abbr:"", ja:"カテーテルアブレーション", note:"不整脈の原因部位を高周波・冷凍で焼灼。AF・WPW・SVT・VTの根治治療。", example:"Catheter ablation of the accessory pathway cured the WPW syndrome.", cat:"treatment", level:"intermediate", dept:"CV" },
{ en:"Cardiac resynchronization therapy", de:"Kardiale Resynchronisationstherapie", abbr:"CRT", ja:"心臓再同期療法", note:"両心室ペーシングによる収縮非同期性の改善。QRS>150ms・LBBB・EF≤35%の心不全に適応。", example:"CRT improved symptoms and EF in the patient with severe heart failure and LBBB.", cat:"treatment", level:"advanced", dept:"CV" },
{ en:"Right heart catheterization", de:"Rechtsherzkatheter", abbr:"RHC", ja:"右心カテーテル検査", note:"スワンガンツカテーテルによる右心系の圧・心拍出量測定。肺高血圧・心不全の確定診断。", example:"Right heart catheterization confirmed precapillary pulmonary hypertension.", cat:"diagnosis", level:"advanced", dept:"CV" },
{ en:"Pulmonary artery pressure", de:"Pulmonalarteriendruck", abbr:"PAP", ja:"肺動脈圧", note:"平均PAP>20mmHgで肺高血圧症。スワンガンツカテーテルで直接測定。右心不全の原因。", example:"Mean pulmonary artery pressure was 35 mmHg, confirming pulmonary hypertension.", cat:"diagnosis", level:"intermediate", dept:"CV" },
// ==================== 呼吸器内科 RESP ====================
{ en:"Forced vital capacity", de:"Forcierte Vitalkapazität", abbr:"FVC", ja:"努力性肺活量", note:"最大吸気後の最大呼気量。正常予測値の80%以上。拘束性障害で低下。", example:"FVC was 68% of predicted, indicating a restrictive pattern.", cat:"diagnosis", level:"intermediate", dept:"RESP" },
{ en:"FEV1/FVC ratio", de:"FEV1/FVC-Quotient", abbr:"Tiffeneau", ja:"1秒率（ティフノー指数）", note:"<70%で閉塞性障害。COPD・喘息の診断基準。<0.7（気管支拡張薬後）がCOPDの定義。", example:"Post-bronchodilator FEV1/FVC ratio of 0.62 confirmed COPD.", cat:"diagnosis", level:"intermediate", dept:"RESP" },
{ en:"Obstructive pattern", de:"Obstruktives Muster", abbr:"", ja:"閉塞性換気障害", note:"FEV1/FVC<70%。気道閉塞による呼気流量低下。COPD・喘息・気管支拡張症の特徴。", example:"Spirometry showed an obstructive pattern with significant bronchodilator reversibility.", cat:"diagnosis", level:"intermediate", dept:"RESP" },
{ en:"Restrictive pattern", de:"Restriktives Muster", abbr:"", ja:"拘束性換気障害", note:"FVC<80%予測値・FEV1/FVC正常または高値。肺線維症・胸膜疾患・肥満・神経筋疾患で出現。", example:"A restrictive pattern on spirometry prompted CT and further evaluation for ILD.", cat:"diagnosis", level:"intermediate", dept:"RESP" },
{ en:"Bronchospasm", de:"Bronchospasmus", abbr:"", ja:"気管支攣縮", note:"気管支平滑筋の収縮による気道狭窄。喘息・アレルギー反応・刺激物吸入で誘発。β2刺激薬が治療。", example:"Bronchospasm was relieved with inhaled salbutamol.", cat:"symptom", level:"intermediate", dept:"RESP" },
{ en:"Sputum production", de:"Sputumproduktion", abbr:"", ja:"喀痰産生", note:"気道からの分泌物産生。色（黄・緑・血性）・粘稠度・量で感染・炎症の程度を評価。", example:"Increased sputum production with green discoloration suggested bacterial exacerbation.", cat:"symptom", level:"basic", dept:"RESP" },
{ en:"Mucus plugging", de:"Schleimpfropf", abbr:"", ja:"粘液栓塞", note:"粘稠な分泌物による気道閉塞。無気肺・感染の原因。吸入療法・気管支鏡で除去。", example:"Mucus plugging caused right lower lobe atelectasis in the postoperative patient.", cat:"diagnosis", level:"intermediate", dept:"RESP" },
{ en:"Respiratory syncytial virus", de:"Respiratorisches Syncytial-Virus", abbr:"RSV", ja:"RSウイルス", note:"小児細気管支炎・老人・免疫不全者の重症肺炎の原因ウイルス。飛沫・接触感染。", example:"RSV bronchiolitis caused respiratory distress in the 3-month-old infant.", cat:"diagnosis", level:"intermediate", dept:"RESP" },
{ en:"Thoracentesis", de:"Thorakozentese", abbr:"", ja:"胸腔穿刺", note:"胸水の診断的・治療的穿刺。Light基準で滲出性・漏出性を鑑別。超音波ガイド下が安全。", example:"Thoracentesis yielded exudative fluid with a pH of 7.1, consistent with empyema.", cat:"diagnosis", level:"intermediate", dept:"RESP" },
{ en:"Light's criteria", de:"Light-Kriterien", abbr:"", ja:"ライト基準", note:"胸水の滲出性・漏出性鑑別基準。蛋白比>0.5 / LDH比>0.6 / 胸水LDH>2/3上限の3基準。", example:"Light's criteria classified the pleural fluid as an exudate, prompting further workup.", cat:"diagnosis", level:"intermediate", dept:"RESP" },
{ en:"Pleurodesis", de:"Pleurodese", abbr:"", ja:"胸膜癒着術", note:"再発性胸水・気胸の予防目的に胸膜腔にタルク・テトラサイクリンを注入して癒着を誘発。", example:"Talc pleurodesis was performed for recurrent malignant pleural effusion.", cat:"treatment", level:"advanced", dept:"RESP" },
{ en:"Tracheostomy care", de:"Tracheostomapflege", abbr:"", ja:"気管切開孔管理", note:"気管切開チューブの固定・吸引・閉塞予防・皮膚ケア。詰まりは致命的になる。緊急交換の準備が必要。", example:"Tracheostomy care included regular suctioning and inner cannula cleaning.", cat:"treatment", level:"intermediate", dept:"RESP" },
// ==================== 消化器内科 GI ====================
{ en:"Hepatic steatosis", de:"Hepatische Steatose", abbr:"", ja:"肝脂肪沈着（脂肪肝）", note:"肝細胞へのトリグリセリド沈着。超音波・MRIで評価。肥満・DM・過剰飲酒が原因。", example:"Hepatic steatosis was found on ultrasound in the obese patient with elevated liver enzymes.", cat:"diagnosis", level:"basic", dept:"GI" },
{ en:"Liver biopsy", de:"Leberbiopsie", abbr:"", ja:"肝生検", note:"経皮的・腹腔鏡下・経頸静脈的に実施。肝疾患の確定診断・線維化評価。出血が最多合併症。", example:"Liver biopsy confirmed the diagnosis of autoimmune hepatitis.", cat:"diagnosis", level:"intermediate", dept:"GI" },
{ en:"Endoscopic ultrasound", de:"Endosonografie", abbr:"EUS", ja:"超音波内視鏡", note:"内視鏡先端の超音波で消化管壁・膵臓・胆道を高解像度で評価。腫瘍のステージング・生検に使用。", example:"EUS showed a hypoechoic mass in the pancreatic head consistent with pancreatic cancer.", cat:"diagnosis", level:"intermediate", dept:"GI" },
{ en:"Colorectal polyp", de:"Kolorektaler Polyp", abbr:"", ja:"大腸ポリープ", note:"大腸粘膜の隆起性病変。腺腫（癌化リスクあり）/ 過形成（低リスク）。内視鏡的切除・経過観察。", example:"Three colorectal polyps were removed during the screening colonoscopy.", cat:"diagnosis", level:"basic", dept:"GI" },
{ en:"Gastrointestinal motility", de:"Gastrointestinale Motilität", abbr:"", ja:"消化管運動", note:"消化管の蠕動運動。低下（麻痺性イレウス・gastroparesis）/ 亢進（過敏性腸症候群）。", example:"Gastrointestinal motility was assessed with a gastric emptying study.", cat:"common", level:"intermediate", dept:"GI" },
{ en:"Prokinetic agent", de:"Prokinetikum", abbr:"", ja:"消化管運動促進薬", note:"メトクロプラミド・モサプリド・エリスロマイシン。胃不全麻痺・逆流症に使用。", example:"A prokinetic agent was prescribed for the diabetic patient with gastroparesis.", cat:"treatment", level:"intermediate", dept:"GI" },
{ en:"H2 blocker", de:"H2-Blocker", abbr:"", ja:"H2受容体拮抗薬", note:"ファモチジン・ラニチジン。胃酸分泌抑制。PPIより作用弱・副作用少。夜間酸分泌抑制に有効。", example:"An H2 blocker was prescribed for mild GERD symptoms.", cat:"treatment", level:"basic", dept:"GI" },
{ en:"Bowel sounds assessment", de:"Darmgeräuschbeurteilung", abbr:"", ja:"腸蠕動音の評価", note:"聴診で腸蠕動音を評価。亢進（腸閉塞早期・過敏性）/ 減弱（麻痺性イレウス・腹膜炎）/ 消失。", example:"Bowel sounds were absent on auscultation, suggesting paralytic ileus.", cat:"diagnosis", level:"basic", dept:"GI" },
{ en:"Rectal examination", de:"Rektale Untersuchung", abbr:"DRE", ja:"直腸指診", note:"前立腺・直腸腫瘤・括約筋緊張・便潜血を評価。下部消化管出血・前立腺疾患の基本診察。", example:"Digital rectal examination revealed a hard irregular mass in the rectum.", cat:"diagnosis", level:"basic", dept:"GI" },
{ en:"Hemorrhoids", de:"Hämorrhoiden", abbr:"", ja:"痔核", note:"内痔核（粘膜下静脈叢の怒張）/ 外痔核（肛門縁外）。出血・脱出・疼痛が症状。保存的〜手術治療。", example:"Grade III hemorrhoids were treated with rubber band ligation.", cat:"diagnosis", level:"basic", dept:"GI" },
{ en:"Anal fissure", de:"Analfissur", abbr:"", ja:"裂肛", note:"肛門管の表在性裂傷。排便時の鋭い疼痛・出血。便秘・硬便が誘因。外用薬・手術で治療。", example:"Anal fissure was managed with topical nitroglycerin and increased fiber intake.", cat:"diagnosis", level:"basic", dept:"GI" },
{ en:"Perianal fistula", de:"Analfistel", abbr:"", ja:"肛門周囲瘻孔", note:"肛門陰窩から発生する瘻孔。クローン病に合併することも。手術（フィステル切開・シートン法）が治療。", example:"Perianal fistula was treated with a draining seton.", cat:"diagnosis", level:"intermediate", dept:"GI" },
// ==================== 神経内科 NEURO ====================
{ en:"Aphasia types", de:"Aphasietypen", abbr:"", ja:"失語症の分類", note:"Broca（運動性・表出障害）/ Wernicke（感覚性・理解障害）/ 全失語（両方）。MRI・言語評価で分類。", example:"The patient had Broca's aphasia with intact comprehension but effortful speech.", cat:"diagnosis", level:"intermediate", dept:"NEURO" },
{ en:"Expressive aphasia", de:"Expressive Aphasie", abbr:"", ja:"表出性失語（ブローカ失語）", note:"発話の流暢性が低下するが理解は保たれる。左前頭葉（ブローカ野）の病変。", example:"Expressive aphasia was present with non-fluent speech but intact comprehension.", cat:"diagnosis", level:"intermediate", dept:"NEURO" },
{ en:"Receptive aphasia", de:"Rezeptive Aphasie", abbr:"", ja:"受容性失語（ウェルニッケ失語）", note:"言語理解が障害されるが発話は流暢（意味不明）。左側頭葉（ウェルニッケ野）の病変。", example:"Receptive aphasia with fluent but meaningless speech suggested Wernicke's area involvement.", cat:"diagnosis", level:"intermediate", dept:"NEURO" },
{ en:"Neglect", de:"Neglect", abbr:"", ja:"半側空間無視", note:"右頭頂葉病変による左側半空間の無視。線分二等分・時計描画で評価。脳卒中後のリハビリ重要。", example:"Left-sided neglect was identified during the stroke rehabilitation assessment.", cat:"diagnosis", level:"intermediate", dept:"NEURO" },
{ en:"Hemianopia", de:"Hemianopsie", abbr:"", ja:"半盲", note:"視野の半側欠損。Homonymous（同名半盲・後頭葉）/ Bitemporal（両耳側・視交叉）。", example:"Right homonymous hemianopia was detected on confrontation visual field testing.", cat:"symptom", level:"intermediate", dept:"NEURO" },
{ en:"Nystagmus", de:"Nystagmus", abbr:"", ja:"眼振", note:"眼球の律動的不随意運動。中枢性（脳幹・小脳）/ 末梢性（前庭器）を鑑別。方向・速相で評価。", example:"Horizontal nystagmus with a fast phase toward the right suggested a left vestibular lesion.", cat:"symptom", level:"intermediate", dept:"NEURO" },
{ en:"Postictal state", de:"Postiktaler Zustand", abbr:"", ja:"発作後状態（ポスティクタル）", note:"けいれん発作後の意識混濁・疲労・錯乱状態。通常数分〜数時間で回復。Todd麻痺を伴うことも。", example:"The postictal state lasted 30 minutes before the patient regained full consciousness.", cat:"diagnosis", level:"intermediate", dept:"NEURO" },
{ en:"Todd's paralysis", de:"Todd-Lähmung", abbr:"", ja:"トッド麻痺", note:"焦点性発作後の一時的な局所神経症状（麻痺）。数時間以内に回復。脳卒中との鑑別が必要。", example:"Todd's paralysis of the left arm resolved within 2 hours of the seizure.", cat:"diagnosis", level:"intermediate", dept:"NEURO" },
{ en:"Intracranial pressure monitoring", de:"Hirndruckmonitoring", abbr:"ICP monitoring", ja:"頭蓋内圧モニタリング", note:"脳室ドレナージ・硬膜下・硬膜外電極で測定。正常<20mmHg。TBI・SAH・水頭症で使用。", example:"ICP monitoring showed sustained elevations above 25 mmHg requiring treatment.", cat:"diagnosis", level:"advanced", dept:"NEURO" },
{ en:"Cushing's triad", de:"Cushing-Reflex", abbr:"", ja:"クッシング三徴", note:"頭蓋内圧亢進の末期サイン。高血圧・徐脈・不規則呼吸の三徴。脳幹ヘルニア直前の緊急サイン。", example:"Cushing's triad of hypertension, bradycardia, and irregular respirations indicated impending herniation.", cat:"diagnosis", level:"intermediate", dept:"NEURO" },
{ en:"Decerebrate posturing", de:"Strecksynergismus", abbr:"", ja:"除脳硬直", note:"上肢伸展・内旋・下肢伸展。脳幹下部〜中脳の障害。GCS運動反応2。予後不良のサイン。", example:"Decerebrate posturing to painful stimuli indicated severe brainstem compromise.", cat:"symptom", level:"intermediate", dept:"NEURO" },
{ en:"Decorticate posturing", de:"Beugesynergismus", abbr:"", ja:"除皮質硬直", note:"上肢屈曲・内旋・下肢伸展。大脳皮質〜内包の障害。GCS運動反応3。除脳硬直より軽症。", example:"Decorticate posturing was noted in the patient with a large hemispheric stroke.", cat:"symptom", level:"intermediate", dept:"NEURO" },
// ==================== 内分泌・代謝科 ENDO ====================
{ en:"Thyroid function test", de:"Schilddrüsenfunktionstest", abbr:"TFT", ja:"甲状腺機能検査", note:"TSH・FT4・FT3を測定。TSHが最も感度が高い。亢進（TSH低下・FT4高値）/ 低下（TSH高値・FT4低値）。", example:"Thyroid function tests showed suppressed TSH with elevated FT4, consistent with hyperthyroidism.", cat:"diagnosis", level:"basic", dept:"ENDO" },
{ en:"Insulin sliding scale", de:"Insulin-Sliding-Scale", abbr:"", ja:"スライディングスケール（インスリン）", note:"血糖値に応じてインスリン投与量を調整する方法。入院中の血糖管理に使用。", example:"An insulin sliding scale was used to manage blood glucose levels during the hospital stay.", cat:"treatment", level:"basic", dept:"ENDO" },
{ en:"Hyperosmolar state", de:"Hyperosmolarer Zustand", abbr:"", ja:"高浸透圧状態", note:"血液浸透圧の上昇。高血糖・高Na血症・脱水で生じる。意識障害・血栓の原因。", example:"The hyperosmolar state was corrected with careful IV fluid replacement.", cat:"diagnosis", level:"intermediate", dept:"ENDO" },
{ en:"Glucagon", de:"Glucagon", abbr:"", ja:"グルカゴン", note:"膵α細胞から分泌。血糖上昇作用。重症低血糖の緊急治療（筋注）。DKAで相対的過剰。", example:"Glucagon 1 mg was injected IM for the unconscious hypoglycemic patient.", cat:"treatment", level:"intermediate", dept:"ENDO" },
{ en:"Thyroid storm", de:"Thyreotoxische Krise", abbr:"", ja:"甲状腺クリーゼ", note:"甲状腺機能亢進症の急性増悪。高体温・頻脈・意識障害。Burch-Wartofsky scoreで診断。死亡率高い。", example:"Thyroid storm was managed with PTU, steroids, beta-blockers, and potassium iodide.", cat:"diagnosis", level:"advanced", dept:"ENDO" },
{ en:"Myxedema coma", de:"Myxödemkoma", abbr:"", ja:"粘液水腫性昏睡", note:"重症甲状腺機能低下症の急性増悪。低体温・意識障害・低換気。T4・T3静注・加温・挿管。", example:"Myxedema coma was treated with IV levothyroxine and supportive care.", cat:"diagnosis", level:"advanced", dept:"ENDO" },
{ en:"Adrenal crisis", de:"Addison-Krise", abbr:"", ja:"副腎クリーゼ", note:"副腎不全の急性増悪。低血圧・低血糖・低Na・高K。ヒドロコルチゾン100mg静注が緊急治療。", example:"Adrenal crisis was treated with IV hydrocortisone 100 mg and normal saline.", cat:"diagnosis", level:"advanced", dept:"ENDO" },
{ en:"Parathyroid hormone", de:"Parathormon", abbr:"PTH", ja:"副甲状腺ホルモン", note:"カルシウム・リン代謝の調節。高Ca血症（PTH高値→原発性副甲状腺機能亢進症）。CKDで二次性亢進。", example:"Elevated PTH with hypercalcemia confirmed primary hyperparathyroidism.", cat:"diagnosis", level:"intermediate", dept:"ENDO" },
{ en:"Glucose tolerance test", de:"Glukosetoleranztest", abbr:"OGTT", ja:"経口ブドウ糖負荷試験", note:"75gOGTT。2時間値≥200mg/dLでDM診断。妊娠糖尿病のスクリーニングにも使用。", example:"Oral glucose tolerance test confirmed gestational diabetes at 28 weeks.", cat:"diagnosis", level:"intermediate", dept:"ENDO" },
// ==================== 血液内科 HEME ====================
{ en:"Packed red blood cells", de:"Erythrozytenkonzentrat", abbr:"pRBC", ja:"濃厚赤血球液", note:"赤血球製剤。Hb<7g/dL（症状あり）または<8g/dL（心疾患）で輸血。1単位で約1g/dL上昇。", example:"Two units of packed red blood cells were transfused for symptomatic anemia.", cat:"treatment", level:"basic", dept:"HEME" },
{ en:"Platelet concentrate", de:"Thrombozytenkonzentrat", abbr:"PLT", ja:"血小板濃厚液", note:"血小板輸血。<10,000/μL（予防的）/ <50,000/μL（出血・手術前）。1単位で約10,000〜20,000/μL上昇。", example:"Platelet concentrate was transfused before the bone marrow biopsy.", cat:"treatment", level:"intermediate", dept:"HEME" },
{ en:"Hematocrit", de:"Hämatokrit", abbr:"Hct", ja:"ヘマトクリット", note:"血液中の赤血球の容積比率。正常男性42〜52%・女性36〜46%。貧血・多血症・脱水の評価。", example:"Hematocrit was 28%, consistent with moderate anemia.", cat:"diagnosis", level:"basic", dept:"HEME" },
{ en:"Mean corpuscular volume", de:"Mittleres Erythrozytenvolumen", abbr:"MCV", ja:"平均赤血球容積", note:"正常80〜100fL。<80（小球性：鉄欠乏・サラセミア）/ >100（大球性：B12・葉酸欠乏・肝疾患）。", example:"MCV of 72 fL indicated microcytic anemia, prompting iron studies.", cat:"diagnosis", level:"basic", dept:"HEME" },
{ en:"Serum ferritin", de:"Serumferritin", abbr:"", ja:"血清フェリチン", note:"鉄貯蔵の指標。低値（鉄欠乏）/ 高値（炎症・肝疾患・血球貪食症候群）。急性相反応蛋白でもある。", example:"Low serum ferritin of 5 ng/mL confirmed iron deficiency anemia.", cat:"diagnosis", level:"basic", dept:"HEME" },
{ en:"TIBC", de:"Totale Eisenbindungskapazität", abbr:"TIBC", ja:"総鉄結合能", note:"トランスフェリンの鉄結合能力。鉄欠乏で上昇・慢性疾患性貧血で低下。血清鉄とセットで評価。", example:"TIBC was elevated with low serum iron, consistent with iron deficiency.", cat:"diagnosis", level:"intermediate", dept:"HEME" },
{ en:"Transferrin saturation", de:"Transferrinsättigung", abbr:"TSAT", ja:"トランスフェリン飽和度", note:"血清鉄/TIBC×100。正常20〜50%。<20%で鉄欠乏・>50%で鉄過剰（ヘモクロマトーシス）。", example:"Transferrin saturation of 12% confirmed iron deficiency.", cat:"diagnosis", level:"intermediate", dept:"HEME" },
{ en:"Neutropenia", de:"Neutropenie", abbr:"", ja:"好中球減少症", note:"好中球絶対数<1500/μL。<500/μLで重症。感染リスク増大。化学療法・骨髄不全・薬剤性。", example:"Severe neutropenia after chemotherapy required prophylactic antibiotics.", cat:"diagnosis", level:"intermediate", dept:"HEME" },
{ en:"Febrile neutropenia protocol", de:"Protokoll für febrile Neutropenie", abbr:"", ja:"発熱性好中球減少症プロトコル", note:"好中球<500/μL＋発熱38℃以上。血液培養2セット→広域抗菌薬即時投与。1時間以内が目標。", example:"Febrile neutropenia protocol was initiated with immediate blood cultures and piperacillin-tazobactam.", cat:"treatment", level:"intermediate", dept:"HEME" },
{ en:"G-CSF", de:"G-CSF", abbr:"G-CSF", ja:"顆粒球コロニー刺激因子", note:"Granulocyte Colony-Stimulating Factor。好中球産生促進。化学療法後の好中球減少予防・治療。", example:"G-CSF was given after chemotherapy to prevent febrile neutropenia.", cat:"treatment", level:"intermediate", dept:"HEME" },
// ==================== 感染症内科 INFECT ====================
{ en:"Gram stain", de:"Gram-Färbung", abbr:"", ja:"グラム染色", note:"細菌の細胞壁構造による染色分類。陽性（青紫・厚い細胞壁）/ 陰性（赤・薄い細胞壁）。治療選択の指針。", example:"Gram stain of the sputum showed gram-positive cocci in clusters, suggesting S. aureus.", cat:"diagnosis", level:"basic", dept:"INFECT" },
{ en:"Culture and sensitivity", de:"Kultur und Resistenzbestimmung", abbr:"C&S", ja:"培養・感受性検査", note:"病原菌の同定と抗菌薬感受性を確認。経験的治療から標的治療への変更（de-escalation）に必須。", example:"Culture and sensitivity results guided a change from broad-spectrum to targeted antibiotic therapy.", cat:"diagnosis", level:"basic", dept:"INFECT" },
{ en:"Septic emboli", de:"Septische Emboli", abbr:"", ja:"敗血症性塞栓", note:"感染性心内膜炎・カテーテル感染から血流を介して遠隔臓器に塞栓。皮膚・眼・脳・肺に多い。", example:"Septic emboli to the lungs were found in the patient with infective endocarditis.", cat:"diagnosis", level:"advanced", dept:"INFECT" },
{ en:"Procalcitonin", de:"Procalcitonin", abbr:"PCT", ja:"プロカルシトニン", note:"細菌感染の炎症マーカー。CRPより特異度高い。敗血症の診断・抗菌薬終了の指標として使用。", example:"Procalcitonin of 8.5 ng/mL supported the diagnosis of bacterial sepsis.", cat:"diagnosis", level:"intermediate", dept:"INFECT" },
{ en:"Clostridium difficile", de:"Clostridium difficile", abbr:"C.diff", ja:"クロストリジウム・ディフィシル感染症", note:"抗菌薬後の偽膜性腸炎。水様性下痢・腹痛・発熱。バンコマイシン経口・フィダキソマイシンで治療。", example:"C. difficile colitis was confirmed by toxin assay after antibiotic treatment.", cat:"diagnosis", level:"intermediate", dept:"INFECT" },
{ en:"ESBL", de:"ESBL", abbr:"ESBL", ja:"基質拡張型β-ラクタマーゼ産生菌", note:"Extended-Spectrum β-Lactamase。ペニシリン・セファロスポリン耐性。カルバペネムが治療の主体。", example:"ESBL-producing E. coli urinary tract infection was treated with ertapenem.", cat:"diagnosis", level:"advanced", dept:"INFECT" },
{ en:"Carbapenem-resistant organism", de:"Carbapenemresistenter Erreger", abbr:"CRO", ja:"カルバペネム耐性菌", note:"KPC・NDM・OXA産生菌。ほぼ全ての抗菌薬に耐性。コリスチン・セフタジジム-アビバクタムが使用可能。", example:"Carbapenem-resistant Klebsiella required combination antibiotic therapy.", cat:"diagnosis", level:"advanced", dept:"INFECT" },
{ en:"Droplet precautions", de:"Tröpfchenprävention", abbr:"", ja:"飛沫感染予防策", note:"インフルエンザ・COVID-19・百日咳。個室または距離確保・サージカルマスク・手指衛生。", example:"Droplet precautions were implemented for the influenza-positive patient.", cat:"treatment", level:"basic", dept:"INFECT" },
{ en:"Airborne precautions", de:"Luftübertragungsprävention", abbr:"", ja:"空気感染予防策", note:"結核・麻疹・水痘。陰圧個室・N95マスク・手指衛生。医療従事者のPPEが必須。", example:"Airborne precautions with a negative pressure room were required for the suspected tuberculosis patient.", cat:"treatment", level:"intermediate", dept:"INFECT" },
// ==================== 腎臓内科 NEPH ====================
{ en:"Uremic symptoms", de:"Urämische Symptome", abbr:"", ja:"尿毒症症状", note:"倦怠感・食欲不振・嘔気・掻痒感・認知機能低下・心嚢炎。腎機能が著しく低下した際に出現。透析適応。", example:"Uremic symptoms including pericarditis prompted emergent initiation of dialysis.", cat:"symptom", level:"intermediate", dept:"NEPH" },
{ en:"Renal osteodystrophy", de:"Renale Osteodystrophie", abbr:"", ja:"腎性骨異栄養症", note:"CKDに伴う骨・ミネラル代謝異常。二次性副甲状腺機能亢進症・低Ca・高P・ビタミンD欠乏が原因。", example:"Renal osteodystrophy was managed with phosphate binders and active vitamin D.", cat:"diagnosis", level:"intermediate", dept:"NEPH" },
{ en:"EPO deficiency", de:"EPO-Mangel", abbr:"", ja:"エリスロポエチン欠乏", note:"CKD性貧血の主因。腎でのEPO産生低下→赤血球産生減少。ESA製剤で補充。", example:"EPO deficiency was the primary cause of anemia in the CKD stage 4 patient.", cat:"diagnosis", level:"intermediate", dept:"NEPH" },
{ en:"Urine protein electrophoresis", de:"Urinproteinelektrophorese", abbr:"UPEP", ja:"尿蛋白電気泳動", note:"尿中蛋白の分画分析。M蛋白（多発性骨髄腫）・Bence Jones蛋白の検出。ネフローゼとの鑑別。", example:"Urine protein electrophoresis showed a monoclonal spike, prompting a bone marrow biopsy.", cat:"diagnosis", level:"advanced", dept:"NEPH" },
{ en:"Vascular access surveillance", de:"Gefäßzugangsüberwachung", abbr:"", ja:"透析用血管アクセスのサーベイランス", note:"AVFの狭窄・血栓・感染を定期的にモニタリング。静脈圧・流量・超音波で評価。", example:"Vascular access surveillance detected a stenosis that was corrected with angioplasty.", cat:"diagnosis", level:"intermediate", dept:"NEPH" },
// ==================== 腫瘍内科 ONCO ====================
{ en:"Eastern Cooperative Oncology Group score", de:"ECOG-Performance-Status", abbr:"ECOG PS", ja:"ECOGパフォーマンスステータス", note:"0（完全活動）〜4（全介護）の5段階。化学療法適応・予後予測の基準として使用。", example:"ECOG PS of 2 indicated the patient could tolerate modified chemotherapy.", cat:"diagnosis", level:"intermediate", dept:"ONCO" },
{ en:"Systemic therapy", de:"Systemtherapie", abbr:"", ja:"全身療法", note:"化学療法・分子標的薬・免疫療法・ホルモン療法の総称。転移性・局所進行癌の主な治療。", example:"Systemic therapy with pembrolizumab was started for the PD-L1 high lung cancer.", cat:"treatment", level:"intermediate", dept:"ONCO" },
{ en:"Cytotoxic chemotherapy", de:"Zytotoxische Chemotherapie", abbr:"", ja:"細胞毒性化学療法", note:"DNA複製・細胞分裂を阻害する薬剤。白金製剤・タキサン・アントラサイクリンなど。骨髄抑制・脱毛が主な副作用。", example:"Cytotoxic chemotherapy with carboplatin and paclitaxel was started for the stage IIIA lung cancer.", cat:"treatment", level:"intermediate", dept:"ONCO" },
{ en:"Chemotherapy cycle", de:"Chemotherapiezyklus", abbr:"", ja:"化学療法サイクル", note:"投与と休薬を繰り返す治療スケジュール。通常1サイクル21日または28日。骨髄回復を待って次サイクル。", example:"Six cycles of chemotherapy were planned, administered every 3 weeks.", cat:"treatment", level:"intermediate", dept:"ONCO" },
{ en:"Dose reduction", de:"Dosisreduktion", abbr:"", ja:"減量（化学療法）", note:"副作用・臓器機能低下で化学療法の用量を減量。75%・50%などの割合で調整。", example:"Dose reduction was required after grade 3 neutropenia in the first cycle.", cat:"treatment", level:"intermediate", dept:"ONCO" },
{ en:"Monoclonal antibody", de:"Monoklonaler Antikörper", abbr:"mAb", ja:"モノクローナル抗体", note:"特定の抗原に結合する人工抗体。トラスツズマブ・ベバシズマブ・リツキシマブなど。「-mab」で終わる。", example:"The monoclonal antibody trastuzumab was added to chemotherapy for HER2-positive breast cancer.", cat:"treatment", level:"intermediate", dept:"ONCO" },
{ en:"Tyrosine kinase inhibitor", de:"Tyrosinkinasehemmer", abbr:"TKI", ja:"チロシンキナーゼ阻害薬", note:"増殖シグナル伝達経路を阻害する分子標的薬。「-tinib」で終わる。EGFR・ALK・BCR-ABLなど標的別に使用。", example:"An EGFR tyrosine kinase inhibitor was selected based on the molecular profiling.", cat:"treatment", level:"intermediate", dept:"ONCO" },
// ==================== 精神科 PSY ====================
{ en:"Mental status examination", de:"Psychopathologische Untersuchung", abbr:"MSE", ja:"精神状態検査", note:"外観・行動・発語・気分・思考・知覚・認知・病識を系統的に評価。精神科診察の基本。", example:"Mental status examination revealed depressed mood, poverty of speech, and impaired concentration.", cat:"diagnosis", level:"basic", dept:"PSY" },
{ en:"Affect", de:"Affekt", abbr:"", ja:"感情表出（アフェクト）", note:"観察される感情の表現。Flat（平坦）/ Blunted（鈍麻）/ Labile（不安定）/ Appropriate（適切）で記録。", example:"Affect was flat with poor eye contact throughout the interview.", cat:"diagnosis", level:"intermediate", dept:"PSY" },
{ en:"Mood", de:"Stimmung", abbr:"", ja:"気分（ムード）", note:"患者が主観的に報告する感情状態。「気分はいかがですか？」と問う。Depressed / Elevated / Anxious / Euthymic。", example:"Mood was reported as depressed for the past two weeks.", cat:"diagnosis", level:"basic", dept:"PSY" },
{ en:"Thought disorder", de:"Denkstörung", abbr:"", ja:"思考障害", note:"思考の形式の異常。連合弛緩・思考散乱・思考滅裂・思考途絶など。統合失調症の特徴的症状。", example:"Thought disorder was evident with loose associations and tangential thinking.", cat:"diagnosis", level:"intermediate", dept:"PSY" },
{ en:"Flight of ideas", de:"Ideenflucht", abbr:"", ja:"観念奔逸", note:"次々と新しい考えが浮かび思考が速くなる状態。躁状態の特徴的症状。発語が速く話題が飛ぶ。", example:"Flight of ideas with pressured speech was consistent with a manic episode.", cat:"symptom", level:"intermediate", dept:"PSY" },
{ en:"Pressured speech", de:"Gedankendruck", abbr:"", ja:"多弁（切迫した発語）", note:"止められないような速くて大量の発語。躁状態・不安・刺激薬の副作用で出現。", example:"Pressured speech and grandiosity were prominent features of the manic episode.", cat:"symptom", level:"intermediate", dept:"PSY" },
{ en:"Suicidal risk assessment", de:"Suizidrisikobewertung", abbr:"", ja:"自殺リスク評価", note:"Columbia Suicide Severity Rating Scale（C-SSRS）等で評価。意図・計画・手段・過去歴を確認。", example:"Suicidal risk assessment revealed passive ideation without plan or intent.", cat:"diagnosis", level:"intermediate", dept:"PSY" },
{ en:"Insight", de:"Krankheitseinsicht", abbr:"", ja:"病識", note:"自分の疾患・症状を認識する能力。Poor insight（病識欠如）は治療アドヒアランス低下の原因。", example:"Insight was poor as the patient denied having any mental illness.", cat:"diagnosis", level:"intermediate", dept:"PSY" },
{ en:"Cognitive behavioral therapy", de:"Kognitive Verhaltenstherapie", abbr:"CBT", ja:"認知行動療法", note:"思考パターン・行動を修正する心理療法。うつ・不安・PTSD・慢性疼痛に有効。", example:"Cognitive behavioral therapy was recommended for the patient with treatment-resistant depression.", cat:"treatment", level:"basic", dept:"PSY" },
// ==================== 小児科 PED ====================
{ en:"Weight-based dosing", de:"Gewichtsbasierte Dosierung", abbr:"", ja:"体重換算投与量", note:"小児の薬剤量はmg/kgで計算。成人の最大量を超えないように確認。誤投与防止のため二重確認。", example:"Weight-based dosing was calculated at 10 mg/kg for the antibiotic.", cat:"common", level:"basic", dept:"PED" },
{ en:"Adjusted age", de:"Korrigiertes Alter", abbr:"", ja:"修正月齢（早産児）", note:"早産児の発達評価に使用。実際の月齢から早産週数を引いた月齢。2歳まで修正月齢で評価。", example:"Developmental milestones were assessed using adjusted age for the 28-week premature infant.", cat:"common", level:"intermediate", dept:"PED" },
{ en:"APGAR score", de:"APGAR-Score", abbr:"", ja:"アプガースコア", note:"出生後1分・5分に評価。Appearance・Pulse・Grimace・Activity・Respirationの5項目。7点以上が正常。", example:"APGAR score was 5 at 1 minute and 8 at 5 minutes after birth.", cat:"diagnosis", level:"basic", dept:"PED" },
{ en:"Neonatal hyperbilirubinemia", de:"Neugeborenenikterus", abbr:"", ja:"新生児高ビリルビン血症", note:"新生児黄疸。生後2〜3日に出現する生理的黄疸と病的黄疸を鑑別。光線療法・交換輸血。", example:"Neonatal hyperbilirubinemia was treated with phototherapy for 48 hours.", cat:"diagnosis", level:"basic", dept:"PED" },
{ en:"Pediatric vital signs", de:"Pädiatrische Vitalzeichen", abbr:"", ja:"小児のバイタルサイン基準値", note:"年齢によって正常値が異なる。新生児：HR120〜160 / 乳児：HR100〜160 / 学童：HR70〜110。RR・BPも年齢別。", example:"Pediatric vital signs were interpreted using age-appropriate reference ranges.", cat:"diagnosis", level:"basic", dept:"PED" },
{ en:"Febrile child management", de:"Fiebermanagement beim Kind", abbr:"", ja:"発熱小児の管理", note:"3ヶ月未満の発熱は重篤感染症を除外。体温>38℃で敗血症スクリーニング。解熱薬・水分補給。", example:"Febrile child management included blood culture, CBC, and LP in the 6-week-old infant.", cat:"treatment", level:"basic", dept:"PED" },
{ en:"Stridor in children", de:"Stridor bei Kindern", abbr:"", ja:"小児の吸気性喘鳴", note:"クループ（吠え声咳）/ 喉頭蓋炎（流涎・前傾位）/ 気道異物を鑑別。重症度評価が重要。", example:"Stridor in the child with barking cough was diagnosed as croup and treated with dexamethasone.", cat:"symptom", level:"intermediate", dept:"PED" },
{ en:"Tanner staging", de:"Tanner-Stadien", abbr:"", ja:"タナー段階（思春期発達）", note:"思春期の二次性徴発達をI〜Vの5段階で評価。乳房・外性器・陰毛の発達で評価。", example:"Tanner staging showed stage III breast development in the 9-year-old girl, suggesting early puberty.", cat:"diagnosis", level:"intermediate", dept:"PED" },
// ==================== 産婦人科 OB ====================
{ en:"Fundal height", de:"Fundustand", abbr:"", ja:"子宮底長", note:"恥骨上縁から子宮底までの距離（cm）。妊娠週数と概ね一致。SGA・LGAのスクリーニング。", example:"Fundal height of 32 cm was appropriate for 32 weeks gestation.", cat:"diagnosis", level:"basic", dept:"OB" },
{ en:"Leopold maneuvers", de:"Leopold-Handgriffe", abbr:"", ja:"レオポルド触診法", note:"4つの手技で胎位（頭位・骨盤位）・胎向・先進部を確認。分娩前の基本的診察。", example:"Leopold maneuvers confirmed a cephalic presentation at 36 weeks.", cat:"diagnosis", level:"intermediate", dept:"OB" },
{ en:"Cervical dilation", de:"Zervixdilatation", abbr:"", ja:"子宮頸管開大", note:"分娩進行の評価。1〜10cm。10cmが全開大。内診で評価。分娩第1期の進行指標。", example:"Cervical dilation was 6 cm on admission, indicating active labor.", cat:"diagnosis", level:"basic", dept:"OB" },
{ en:"Cervical effacement", de:"Zervixverkürzung", abbr:"", ja:"子宮頸管短縮（展退）", note:"分娩に伴う頸管の短縮・薄さ。0〜100%で表現。100%で完全展退。開大とセットで評価。", example:"Cervical effacement was 80% with 4 cm dilation.", cat:"diagnosis", level:"intermediate", dept:"OB" },
{ en:"Fetal presentation", de:"Kindslage", abbr:"", ja:"胎位", note:"先進部（子宮口に最初に触れる部位）の種類。頭位（最多）/ 骨盤位（3〜4%）/ 横位（稀）。", example:"Fetal presentation was confirmed as vertex by ultrasound at 37 weeks.", cat:"diagnosis", level:"basic", dept:"OB" },
{ en:"Amniotic fluid index", de:"Fruchtwasserindex", abbr:"AFI", ja:"羊水インデックス", note:"超音波で4象限の羊水ポケットの和。正常5〜25cm。<5cm（羊水過少）/ >25cm（羊水過多）。", example:"Amniotic fluid index of 3 cm indicated oligohydramnios requiring close monitoring.", cat:"diagnosis", level:"intermediate", dept:"OB" },
{ en:"Oxytocin induction", de:"Oxytozin-Einleitung", abbr:"", ja:"オキシトシン誘発（分娩誘発）", note:"子宮収縮誘発薬。点滴静注で子宮収縮を誘発。胎児モニタリングが必須。過強陣痛・胎児機能不全に注意。", example:"Oxytocin induction was started at 41 weeks for post-term pregnancy.", cat:"treatment", level:"intermediate", dept:"OB" },
// ==================== 皮膚科 DERM ====================
{ en:"Erythema", de:"Erythem", abbr:"", ja:"紅斑", note:"皮膚の発赤・充血。炎症・感染・薬疹・アレルギーで出現。圧迫で消退するものと消退しないものを鑑別。", example:"A spreading erythema around the wound suggested early cellulitis.", cat:"symptom", level:"basic", dept:"DERM" },
{ en:"Purpura", de:"Purpura", abbr:"", ja:"紫斑", note:"皮膚・粘膜への出血による変色。圧迫で消退しない。血小板減少・血管炎・凝固障害を示唆。", example:"Non-blanching purpura was a sign of thrombocytopenic purpura.", cat:"symptom", level:"intermediate", dept:"DERM" },
{ en:"Petechiae", de:"Petechien", abbr:"", ja:"点状出血（ペテキア）", note:"針頭大の皮膚内出血点。圧迫で消退しない。血小板減少・敗血症・感染性心内膜炎を示唆。", example:"Petechiae on the lower extremities raised concern for meningococcemia.", cat:"symptom", level:"intermediate", dept:"DERM" },
{ en:"Vesicle", de:"Vesikel", abbr:"", ja:"水疱（小水疱）", note:"皮膚内の透明な液体貯留（<0.5cm）。帯状疱疹・水痘・ウイルス性皮膚炎で出現。", example:"Multiple vesicles on an erythematous base were consistent with herpes zoster.", cat:"symptom", level:"basic", dept:"DERM" },
{ en:"Bulla", de:"Bulla", abbr:"", ja:"大水疱", note:"皮膚内の大きな液体貯留（>0.5cm）。天疱瘡・類天疱瘡・熱傷・SJS/TENで出現。", example:"Bullae larger than 1 cm developed in the patient with pemphigus vulgaris.", cat:"symptom", level:"intermediate", dept:"DERM" },
{ en:"Plaque", de:"Plaque", abbr:"", ja:"局面（プラーク）", note:"皮膚表面から隆起した平坦な病変（>1cm）。乾癬・湿疹・皮膚T細胞リンパ腫で出現。", example:"Silvery plaques on the extensor surfaces were classic findings of plaque psoriasis.", cat:"symptom", level:"basic", dept:"DERM" },
{ en:"Lichenification", de:"Lichenifikation", abbr:"", ja:"苔癬化", note:"慢性掻破による皮膚の肥厚・硬化。格子状のひび割れ・色素沈着。慢性湿疹に特徴的。", example:"Lichenification of the antecubital fossa was a sign of chronic atopic dermatitis.", cat:"symptom", level:"intermediate", dept:"DERM" },
{ en:"Koebner phenomenon", de:"Köbner-Phänomen", abbr:"", ja:"ケブネル現象", note:"外傷部位に皮膚疾患が誘発される現象。乾癬・白斑・扁平苔癬で出現。", example:"Koebner phenomenon was noted at the site of a scar in the psoriasis patient.", cat:"diagnosis", level:"intermediate", dept:"DERM" },
{ en:"Nikolsky sign", de:"Nikolski-Zeichen", abbr:"", ja:"ニコルスキー徴候", note:"正常皮膚をこすると表皮が剥離する現象。天疱瘡・TEN・SSSS（ブドウ球菌性熱傷様皮膚症候群）で陽性。", example:"Positive Nikolsky sign supported the diagnosis of pemphigus vulgaris.", cat:"diagnosis", level:"intermediate", dept:"DERM" },
// ==================== 泌尿器科 URO ====================
{ en:"Lower urinary tract symptoms", de:"Untere Harntraktsymptome", abbr:"LUTS", ja:"下部尿路症状", note:"蓄尿症状（頻尿・尿意切迫）・排尿症状（尿勢低下・残尿感）・排尿後症状。BPH・過活動膀胱が原因。", example:"Lower urinary tract symptoms including frequency and weak stream were caused by BPH.", cat:"symptom", level:"basic", dept:"URO" },
{ en:"Urethral stricture", de:"Harnröhrenstriktur", abbr:"", ja:"尿道狭窄", note:"尿道の瘢痕性狭窄。外傷・感染・医原性が原因。排尿困難・尿閉・再発性UTI。尿道形成術。", example:"Urethral stricture was treated with direct vision internal urethrotomy.", cat:"diagnosis", level:"intermediate", dept:"URO" },
{ en:"Cystitis", de:"Zystitis", abbr:"", ja:"膀胱炎", note:"膀胱の細菌感染。排尿痛・頻尿・血尿。大腸菌が最多原因菌。短期間の抗菌薬投与が治療。", example:"Uncomplicated cystitis was treated with a 3-day course of trimethoprim.", cat:"diagnosis", level:"basic", dept:"URO" },
{ en:"Pyelonephritis", de:"Pyelonephritis", abbr:"", ja:"腎盂腎炎", note:"腎・腎盂の細菌感染。発熱・悪寒・CVA叩打痛・尿路症状。入院か外来かは重症度で判断。", example:"Acute pyelonephritis was treated with IV ceftriaxone until oral antibiotics were tolerated.", cat:"diagnosis", level:"basic", dept:"URO" },
{ en:"Urinary stone", de:"Harnstein", abbr:"", ja:"尿路結石", note:"腎・尿管・膀胱の結石。疝痛・血尿・感染。CT（感度最高）で診断。水分摂取・鎮痛・結石排出。", example:"A 6 mm ureteral stone was managed conservatively with hydration and analgesics.", cat:"diagnosis", level:"basic", dept:"URO" },
// ==================== 眼科 OPH ====================
{ en:"Visual acuity testing", de:"Sehschärfeprüfung", abbr:"VA", ja:"視力検査", note:"Snellen視力表または対数視力表で評価。遠見・近見を別々に測定。矯正視力と裸眼視力を記録。", example:"Visual acuity was 20/200 uncorrected and 20/20 with glasses.", cat:"diagnosis", level:"basic", dept:"OPH" },
{ en:"Intraocular pressure elevation", de:"Erhöhter Augeninnendruck", abbr:"", ja:"眼圧上昇", note:"正常10〜21mmHg。>21mmHgで高眼圧症。急性閉塞隅角緑内障は60〜80mmHgまで急上昇。", example:"Intraocular pressure was 42 mmHg, indicating acute angle-closure glaucoma.", cat:"diagnosis", level:"intermediate", dept:"OPH" },
{ en:"Corneal abrasion", de:"Hornhautabrasio", abbr:"", ja:"角膜擦過傷", note:"角膜上皮の損傷。眼痛・流涙・異物感・光過敏。フルオレセイン染色で確認。抗菌眼軟膏・眼帯。", example:"Corneal abrasion was confirmed with fluorescein staining under blue light.", cat:"diagnosis", level:"basic", dept:"OPH" },
{ en:"Hyphema", de:"Hyphaema", abbr:"", ja:"前房出血", note:"前房内への出血。眼球打撲後に多い。安静・眼圧管理・外傷原因の評価が必要。", example:"Hyphema following blunt eye trauma was managed with strict activity restriction.", cat:"diagnosis", level:"intermediate", dept:"OPH" },
// ==================== 耳鼻咽喉科 ENT ====================
{ en:"Conductive hearing loss", de:"Schallleitungsschwerhörigkeit", abbr:"", ja:"伝音性難聴", note:"外耳〜中耳の障害による難聴。中耳炎・耳硬化症・耳垢栓塞が原因。骨導は保たれる。", example:"Conductive hearing loss was caused by otosclerosis and improved with stapedectomy.", cat:"diagnosis", level:"intermediate", dept:"ENT" },
{ en:"Sensorineural hearing loss", de:"Schallempfindungsschwerhörigkeit", abbr:"SNHL", ja:"感音性難聴", note:"内耳・聴神経の障害による難聴。老人性・騒音性・ウイルス性が多い。補聴器・人工内耳。", example:"Sensorineural hearing loss at high frequencies was consistent with noise-induced hearing loss.", cat:"diagnosis", level:"intermediate", dept:"ENT" },
{ en:"Otoscopy", de:"Otoskopie", abbr:"", ja:"耳鏡検査", note:"耳鏡で外耳道・鼓膜を観察。発赤・穿孔・液面・真珠腫を確認。中耳炎・外耳炎の基本評価。", example:"Otoscopy revealed a bulging red tympanic membrane consistent with acute otitis media.", cat:"diagnosis", level:"basic", dept:"ENT" },
{ en:"Epistaxis management", de:"Epistaxisbehandlung", abbr:"", ja:"鼻出血の管理", note:"前方鼻出血（キーゼルバッハ部位・圧迫止血）/ 後方鼻出血（バルーンタンポナーデ・内視鏡止血）。", example:"Posterior epistaxis was controlled with a nasal balloon catheter.", cat:"treatment", level:"intermediate", dept:"ENT" },
{ en:"Foreign body in airway", de:"Fremdkörper in den Atemwegen", abbr:"", ja:"気道異物", note:"小児に多い。咳・喘鳴・窒息。ハイムリック法（意識あり）/ CPR（意識なし）/ 気管支鏡で除去。", example:"A foreign body in the right bronchus was removed by rigid bronchoscopy.", cat:"diagnosis", level:"intermediate", dept:"ENT" },
// ==================== 放射線科 RAD ====================
{ en:"Windowing", de:"Fensterung", abbr:"", ja:"ウインドウ設定（CT読影）", note:"CT画像の表示コントラスト調整。肺野（W1500/L-600）/ 縦隔（W400/L40）/ 骨（W2000/L400）/ 脳（W80/L40）。", example:"Windowing was adjusted to lung settings to better evaluate the pulmonary nodules.", cat:"diagnosis", level:"intermediate", dept:"RAD" },
{ en:"Contrast enhancement", de:"Kontrastmittelanreicherung", abbr:"", ja:"造影増強効果", note:"造影剤投与後のCT/MRIでの信号・密度上昇。腫瘍・炎症・血管病変の評価に重要。", example:"Rim enhancement of the lesion suggested an abscess rather than a solid tumor.", cat:"diagnosis", level:"intermediate", dept:"RAD" },
{ en:"Perfusion imaging", de:"Perfusionsbildgebung", abbr:"", ja:"灌流画像", note:"CT/MRIで組織の血流を評価。脳卒中のpenumbra（虚血半暗帯）評価・心筋虚血の診断に使用。", example:"CT perfusion imaging identified salvageable penumbra, guiding the decision for thrombectomy.", cat:"diagnosis", level:"advanced", dept:"RAD" },
{ en:"MRA", de:"MR-Angiografie", abbr:"MRA", ja:"MR血管造影", note:"MRIで血管を描出。脳・頸部・腎・末梢血管の非侵襲的評価。造影・非造影の両方がある。", example:"MRA of the brain showed a 7 mm aneurysm at the MCA bifurcation.", cat:"diagnosis", level:"intermediate", dept:"RAD" },
{ en:"Interventional procedure", de:"Interventioneller Eingriff", abbr:"", ja:"インターベンション手技", note:"画像ガイド下の低侵襲治療。塞栓術・ドレナージ・生検・血管形成術・ステント留置など。", example:"An interventional procedure was performed to embolize the bleeding hepatic artery.", cat:"treatment", level:"intermediate", dept:"RAD" },
// ==================== 麻酔科 ANES ====================
{ en:"ASA classification", de:"ASA-Klassifikation", abbr:"ASA PS", ja:"ASA身体状態分類", note:"術前リスク評価。I（健常）〜VI（脳死ドナー）の6段階。IIIからリスク増大。緊急はEを付加。", example:"ASA class III was assigned due to the patient's poorly controlled diabetes and hypertension.", cat:"diagnosis", level:"basic", dept:"ANES" },
{ en:"Preoperative fasting", de:"Präoperatives Fasten", abbr:"NPO", ja:"術前絶食", note:"固形食：6時間前 / 牛乳：6時間 / 清澄液体：2時間 / 母乳：4時間が標準。誤嚥性肺炎の予防。", example:"Preoperative fasting was confirmed — the patient had nothing by mouth for 8 hours.", cat:"common", level:"basic", dept:"ANES" },
{ en:"Intraoperative monitoring", de:"Intraoperatives Monitoring", abbr:"", ja:"術中モニタリング", note:"ECG・SpO2・ETCO2・血圧（非観血/観血）・体温・尿量が基本。手術の種類でNMT・BIS・TEEを追加。", example:"Intraoperative monitoring included invasive arterial blood pressure and cardiac output measurement.", cat:"treatment", level:"basic", dept:"ANES" },
{ en:"Emergence from anesthesia", de:"Ausleitung der Anästhesie", abbr:"", ja:"麻酔覚醒", note:"手術終了後の麻酔薬漸減・拮抗薬投与による意識回復。興奮期・喉頭痙攣・悪心に注意。", example:"Smooth emergence from anesthesia was achieved with gradual reduction of volatile anesthetic.", cat:"treatment", level:"intermediate", dept:"ANES" },
{ en:"Laryngospasm", de:"Laryngospasmus", abbr:"", ja:"喉頭痙攣", note:"喉頭筋の反射的痙攣による気道閉塞。麻酔覚醒時・小児に多い。陽圧換気・スキソリン少量で治療。", example:"Laryngospasm after extubation was relieved with jaw thrust and positive pressure ventilation.", cat:"diagnosis", level:"intermediate", dept:"ANES" },
// ==================== 共通 GEN ====================
{ en:"I need to check your temperature.", abbr:"", ja:"体温を測らせてください。", note:"体温測定前の一言。腋窩・口腔・鼓膜・直腸など測定部位を伝える。", example:"I need to check your temperature — I'll use this ear thermometer.", cat:"common", level:"basic", dept:"GEN", de:"Ich muss Ihre Temperatur messen." },
{ en:"Can you take a deep breath and hold it?", abbr:"", ja:"深呼吸をして、息を止めてもらえますか？", note:"胸部X線撮影・腹部触診時の指示。最大吸気位での撮影・診察が目的。", example:"Can you take a deep breath and hold it? I'm going to take the X-ray now.", cat:"common", level:"basic", dept:"GEN", de:"Können Sie tief einatmen und die Luft anhalten?" },
{ en:"Please roll onto your side.", abbr:"", ja:"横向きになってください。", note:"腰椎穿刺・浣腸・肛門診察・体位変換の指示。", example:"Please roll onto your side for the lumbar puncture.", cat:"common", level:"basic", dept:"GEN", de:"Bitte drehen Sie sich auf die Seite." },
{ en:"Can you squeeze my fingers?", abbr:"", ja:"私の指を握ってもらえますか？", note:"上肢の握力・筋力を簡易評価するための指示。脳卒中・神経障害の評価に使用。", example:"Can you squeeze my fingers as hard as you can with both hands?", cat:"common", level:"basic", dept:"GEN", de:"Können Sie meine Finger drücken?" },
{ en:"Can you push down with your foot?", abbr:"", ja:"足で踏み込んでもらえますか？", note:"足背屈・底屈の筋力評価。L4-S1神経根・足背・足底の筋力を確認。", example:"Can you push down with your foot against my hand?", cat:"common", level:"basic", dept:"GEN", de:"Können Sie mit dem Fuß nach unten drücken?" },
{ en:"Follow my finger with your eyes.", abbr:"", ja:"指の動きを目で追ってください。", note:"眼球運動・追視の評価指示。脳神経III・IV・VIの機能を確認。", example:"Follow my finger with your eyes without moving your head.", cat:"common", level:"basic", dept:"GEN", de:"Folgen Sie meinem Finger mit den Augen." },
{ en:"Stick out your tongue.", abbr:"", ja:"舌を出してください。", note:"舌下神経（CNXII）の評価。偏位（障害側）・萎縮・線維束攣縮を確認。", example:"Stick out your tongue — I want to check for any weakness.", cat:"common", level:"basic", dept:"GEN", de:"Strecken Sie die Zunge heraus." },
{ en:"Say 'ah'.", abbr:"", ja:"「アー」と言ってください。", note:"軟口蓋・迷走神経（CNX）の評価。口蓋垂の偏位・咽頭反射の確認。", example:"Say 'ah' so I can see the back of your throat.", cat:"common", level:"basic", dept:"GEN", de:"Sagen Sie 'Ah'." },
{ en:"Can you walk heel to toe?", abbr:"", ja:"踵つま先歩きをしてもらえますか？", note:"小脳機能・バランスの評価。タンデム歩行（一直線上に踵とつま先を交互に置く歩行）。", example:"Can you walk heel to toe in a straight line for me?", cat:"common", level:"basic", dept:"GEN", de:"Können Sie Ferse-zu-Zehe gehen?" },
{ en:"Squeeze test", abbr:"", ja:"スクイーズテスト（腓腹筋圧迫）", note:"アキレス腱断裂の診断（Thompson test）。腹臥位で腓腹筋を圧迫し足の底屈を確認。消失で断裂。", example:"Squeeze test was negative, indicating an intact Achilles tendon.", cat:"diagnosis", level:"intermediate", dept:"GEN", de:"Squeeze-Test" },
{ en:"What is your pain like on a scale from zero to ten?", abbr:"", ja:"痛みは0から10のスケールでどのくらいですか？", note:"NRS（Numeric Rating Scale）。0：無痛 / 10：最大の痛み。治療前後の比較に使用。", example:"What is your pain like on a scale from zero to ten, where ten is the worst pain imaginable?", cat:"common", level:"basic", dept:"GEN", de:"Wie stark sind Ihre Schmerzen auf einer Skala von null bis zehn?" },
{ en:"I'm going to refer you back to your GP.", abbr:"", ja:"かかりつけ医に紹介状を書きます。", note:"専門診療後の逆紹介。経過観察・継続管理をかかりつけ医に依頼する際の説明。", example:"I'm going to refer you back to your GP for ongoing management.", cat:"common", level:"basic", dept:"GEN", de:"Ich werde Sie zurück an Ihren Hausarzt überweisen." },
{ en:"You need to be admitted to hospital.", abbr:"", ja:"入院が必要です。", note:"入院の必要性を伝える直接的な表現。理由・期間・次のステップを合わせて説明する。", example:"You need to be admitted to hospital for further tests and treatment.", cat:"common", level:"basic", dept:"GEN", de:"Sie müssen ins Krankenhaus aufgenommen werden." },
{ en:"I'll arrange for a specialist to see you.", abbr:"", ja:"専門家に診てもらえるように手配します。", note:"院内コンサルテーション・専門医受診の手配を伝える。患者の安心と次のステップの明確化。", example:"I'll arrange for a specialist to see you today.", cat:"common", level:"basic", dept:"GEN", de:"Ich werde einen Spezialisten für Sie arrangieren." },
{ en:"There's nothing seriously wrong.", abbr:"", ja:"深刻な問題はありません。", note:"重篤疾患を除外できた際の安心を伝える表現。ただし症状の経過観察の指示も合わせて伝える。", example:"There's nothing seriously wrong, but I'd like you to come back if the symptoms persist.", cat:"common", level:"basic", dept:"GEN", de:"Es ist nichts Ernstes." },
{ en:"We'll need to monitor you closely.", abbr:"", ja:"注意深く経過を観察する必要があります。", note:"経過観察が必要な患者への説明。何を観察するか・いつ再評価するかを具体的に伝える。", example:"We'll need to monitor you closely over the next few hours.", cat:"common", level:"basic", dept:"GEN", de:"Wir müssen Sie genau beobachten." },
];
